previewCss:
.darma-loader-darma-custom-292 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #2563eb);
  --g:linear-gradient(90deg,var(--loader-color, #2563eb),var(--loader-secondary-color, #38bdf8)) no-repeat text;
  background: var(--g) 0,var(--g) 100%,var(--g) 0 0,var(--g) 0 100%;
  animation: darma-loader-darma-custom-292-l5 2s linear infinite;
}
.darma-loader-darma-custom-292:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-292-l5 {
  0%,100%{background-size: 0   100%,0   100%,100% 0  ,100% 0  }
  50%    {background-size: 55% 100%,55% 100%,100% 0  ,100% 0  }
  50.01% {background-size: 0   100%,0   100%,100% 55%,100% 55%}
}

